pub fn consumed(bytes: []const u8) usize {
    /// Return the byte count consumed by the parser.
    return bytes.len;
}

const Parser = struct {
    pub fn parse(self: *Parser, bytes: []const u8) !void {
        /// Parse the input into the current document.
        try self.parseBytes(bytes);
    }

    fn parseBytes(self: *Parser, bytes: []const u8) !void {
        _ = self;
        _ = bytes;
    }
};

const Parser = struct {
    /// Number of bytes consumed by the parser.
    consumed: usize,

    /// Parse bytes into the current document.
    pub fn parse(bytes: []const u8) void {
        // Implementation note, not generated API docs.
        _ = bytes;
    }
};

const Kind = enum {
    /// String token.
    string,
    /// Number token.
    number,
};
